#include "GRADIENTADCLP.h" // <-- NOTE THIS FILE WAS AUTO GENERATED by GENERATECLP()

#include <itkImage.h>
#include <itkImageFileReader.h>
#include <itkImageFileWriter.h>
#include <itkGradientAnisotropicDiffusionImageFilter.h>
#include <iostream>

int main (int argc, char * argv[])
{
  PARSE_ARGS;  // <--- This is always the first line and is defined in SimpleThresholdCLP.h

  // 1. Set reader
  using PixelType = float;
  constexpr unsigned int Dimension = 3;
  using ImageType = itk::Image<PixelType, Dimension>;

  // 2. Set reader
  using ReaderType = itk::ImageFileReader<ImageType>;
  auto reader = ReaderType::New();
  reader->SetFileName(input);

  // 3. Set filter
  using FilterType = itk::GradientAnisotropicDiffusionImageFilter<ImageType, ImageType>;

  auto filter = FilterType::New();
  filter->SetInput(reader->GetOutput());
  filter->SetConductanceParameter(conductance);
  filter->SetTimeStep(timeStep);
  filter->SetNumberOfIterations(iterations);

  // 4. Set writer
  using WriterType = itk::ImageFileWriter<ImageType>;
  auto writer = WriterType::New();
  writer->SetFileName(output);
  writer->SetInput(filter->GetOutput());

  // 5. Execute pipeline and catch exceptions
  try
  {
    writer->Update();
  }
  catch (const itk::ExceptionObject & e)
  {
    std::cerr << "Error: " << e << std::endl;
    return EXIT_FAILURE;
  }

  std::cout << "The input volume is: " << input << std::endl;
  std::cout << "The output volume is: " << output << std::endl;
  return EXIT_SUCCESS;
}
